// SPIKE B ARTIFACT — clean-room reference converter for the cluster-reordering
// spike. This is NOT the production engine. It is an independent
// re-implementation authored from the cited mapping research
// (docs/phase0/findings/06-mapping-research.md), built to answer ONE question:
//
//   Can Bengali cluster reordering (pre-base vowels + reph), plus NFC
//   composition of o-kar/au-kar, be implemented correctly and independently?
//
// It is tested by running it through the corpus harness and checking whether it
// AGREES with the corpus `expected` values — which were generated by a DIFFERENT
// independent oracle (rabiulislam-xyz). Two independent implementations
// converging on the frozen corpus is the spike's GREEN signal.
//
// Scope: covers the glyph set used by the corpus (Bijoy/SutonnyMJ subset). It is
// intentionally small; completeness of the glyph map is mundane Phase-4 work.

// --- Bengali code points (named for readability) ---
const VIRAMA = '্';
const NUKTA = '়';

// Glyph map: Bijoy/SutonnyMJ source char -> Unicode component(s), in the order
// the glyph implies (pre-base vowels are mapped in place; reordering happens
// in a later pass). Authored from the cited research, not copied from any
// Mukti-lineage code.
const MAP = {
  // independent vowels ('Av' is a 2-char key, matched before 'A')
  'Av': 'আ', 'A': 'অ', 'B': 'ই', 'C': 'ঈ', 'D': 'উ',
  'E': 'ঊ', 'F': 'ঋ', 'G': 'এ', 'H': 'ঐ', 'I': 'ও',
  'J': 'ঔ',
  // consonants
  'K': 'ক', 'L': 'খ', 'M': 'গ', 'N': 'ঘ', 'O': 'ঙ',
  'P': 'চ', 'Q': 'ছ', 'R': 'জ', 'S': 'ঝ', 'T': 'ঞ',
  'U': 'ট', 'V': 'ঠ', 'W': 'ড', 'X': 'ঢ', 'Y': 'ণ',
  'Z': 'ত', '_': 'থ', '`': 'দ', 'a': 'ধ', 'b': 'ন',
  'c': 'প', 'd': 'ফ', 'e': 'ব', 'f': 'ভ', 'g': 'ম',
  'h': 'য', 'i': 'র', 'j': 'ল', 'k': 'শ', 'l': 'ষ',
  'm': 'স', 'n': 'হ',
  // nukta consonants (NFC-decomposed: base + U+09BC)
  'o': 'ড' + NUKTA, 'p': 'ঢ' + NUKTA, 'q': 'য' + NUKTA,
  // vowel signs (kar) — w/‡/†/ˆ/‰ are pre-base (reordered later)
  'v': 'া', 'w': 'ি', 'x': 'ী', 'y': 'ু', 'z': 'ু',
  '~': 'ূ', '„': 'ৃ', '‡': 'ে', '†': 'ে',
  'ˆ': 'ৈ', '‰': 'ৈ', 'Š': 'ৗ',
  // signs
  's': 'ং', 't': 'ঃ', 'u': 'ঁ', 'r': 'ৎ', '|': '।',
  '&': VIRAMA,
  // digits
  '0': '০', '1': '১', '2': '২', '3': '৩', '4': '৪',
  '5': '৫', '6': '৬', '7': '৭', '8': '৮', '9': '৯',
  // pre-formed conjunct / phala glyph slots (logical order already)
  '¦': VIRAMA + 'ব',           // ্ব
  '¨': VIRAMA + 'য',           // ্য (ya-phala)
  '©': 'র' + VIRAMA,           // র্ (reph marker — reordered later)
  '¯': 'স' + VIRAMA,           // স্ (half sa)
  '^': VIRAMA + 'ব',           // ্ব (half ba)
  '³': 'ক' + VIRAMA + 'ত', // ক্ত
  'µ': 'ক' + VIRAMA + 'র', // ক্র
  '¶': 'ক' + VIRAMA + 'ষ', // ক্ষ
  'ÿ': 'ক' + VIRAMA + 'ষ', // ক্ষ
  '¹': 'জ' + VIRAMA + 'ঞ', // জ্ঞ
  '½': 'ঙ' + VIRAMA + 'গ', // ঙ্গ
  'Î': 'ত' + VIRAMA + 'র', // ত্র
  'Ö': VIRAMA + 'র',           // ্র (ra-phala)
  '×': 'দ' + VIRAMA + 'ধ', // দ্ধ
  'œ': VIRAMA + 'ন',           // ্ন
};

const KEY_LENS = [...new Set(Object.keys(MAP).map((k) => k.length))].sort((a, b) => b - a);

// Character classes for reordering.
const CONS = 'ক-হ';          // Bengali consonants (incl. র)
const PRE_BASE = 'িেৈ';  // i-kar, e-kar, ai-kar (drawn left)
// A "consonant unit": a consonant, optional nukta, then any number of
// (virama + consonant) for conjuncts.
const CUNIT = `[${CONS}]${NUKTA}?(?:${VIRAMA}[${CONS}]${NUKTA}?)*`;

const REPH = 'র' + VIRAMA;

// URL / email runs are passed through untouched (their ASCII must not be mapped).
const PROTECT = /([A-Za-z][A-Za-z0-9+.-]*:\/\/[^\s]+|www\.[^\s]+|[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,})/g;

function mapGlyphs(text) {
  let out = '';
  let i = 0;
  while (i < text.length) {
    let matched = false;
    for (const len of KEY_LENS) {
      const slice = text.substr(i, len);
      if (Object.prototype.hasOwnProperty.call(MAP, slice)) {
        out += MAP[slice];
        i += len;
        matched = true;
        break;
      }
    }
    if (!matched) {
      out += text[i];
      i += 1;
    }
  }
  return out;
}

function reorder(s) {
  // 1. collapse accidental double virama (e.g. স্ + ্ব -> স্ব)
  s = s.replace(new RegExp(VIRAMA + VIRAMA, 'g'), VIRAMA);
  // 2. reph: a consonant immediately followed by র্ -> র্ before that consonant
  //    (Bijoy stores reph after its base; Unicode stores it at cluster start)
  s = s.replace(new RegExp(`([${CONS}])${REPH}`, 'g'), `${REPH}$1`);
  // 3. pre-base vowels drawn left -> stored after their consonant unit
  s = s.replace(new RegExp(`([${PRE_BASE}])(${CUNIT})`, 'g'), '$2$1');
  return s;
}

// Set of every single character that appears in a Bijoy source key. If a run
// contains NONE of these it is not Bijoy (already Unicode / plain text), so the
// converter is a guaranteed no-op on it. This is the design rule that makes the
// engine idempotent: convert(convert(x)) === convert(x), because the output of a
// conversion contains no Bijoy source glyphs and is therefore left untouched on
// any subsequent pass. (The prior engine's reorder lacked this guard and
// corrupted its own output.)
const SOURCE_GLYPHS = new Set();
for (const key of Object.keys(MAP)) for (const ch of key) SOURCE_GLYPHS.add(ch);

function hasBijoy(s) {
  for (const ch of s) if (SOURCE_GLYPHS.has(ch)) return true;
  return false;
}

export function convert(input) {
  if (!input) return input;
  // Idempotency / no-op guard: nothing to convert if there are no Bijoy glyphs.
  if (!hasBijoy(input)) return input.normalize('NFC');
  // protect URLs/emails
  const parts = input.split(PROTECT);
  let out = '';
  for (let k = 0; k < parts.length; k++) {
    const seg = parts[k];
    // odd indices are the captured protected runs
    if (k % 2 === 1) {
      out += seg;
    } else {
      out += reorder(mapGlyphs(seg));
    }
  }
  return out.normalize('NFC');
}

export default convert;
